messages.content:
Fix this XState v4 code to v5 idioms:

```js
const counter = Machine({
  id: 'counter',
  context: { count: 0 },
  initial: 'active',
  states: {
    active: {
      on: {
        INC: { actions: assign({ count: (ctx) => ctx.count + 1 }) },
        RESET: { actions: assign({ count: (_ctx) => 0 }) }
      }
    }
  }
});
```

Replace the v4 `Machine(...)` factory with `setup({ types }).createMachine(...)`, and switch `assign` callbacks to the v5 object-destructured `({ context })` signature.

```typescript
import { setup, assign } from 'xstate';

export const counterMachine = setup({
  types: {
    context: {} as { count: number },
    events: {} as { type: 'INC' } | { type: 'RESET' }
  }
}).createMachine({
  id: 'counter',
  context: { count: 0 },
  initial: 'active',
  states: {
    active: {
      on: {
        INC: { actions: assign({ count: ({ context }) => context.count + 1 }) },
        RESET: { actions: assign({ count: () => 0 }) }
      }
    }
  }
});
```

Convert this XState v4 machine to v5 using setup().createMachine:

```js
const toggle = Machine({
  id: 'toggle',
  initial: 'off',
  states: {
    off: { on: { FLIP: 'on' } },
    on:  { on: { FLIP: 'off' } }
  }
});
```

The v4 `Machine` factory becomes `setup().createMachine`. Events get a typed union via `setup.types` so the transition keys are checked.

```typescript
import { setup } from 'xstate';

export const toggleMachine = setup({
  types: {
    events: {} as { type: 'FLIP' }
  }
}).createMachine({
  id: 'toggle',
  initial: 'off',
  states: {
    off: { on: { FLIP: 'on' } },
    on:  { on: { FLIP: 'off' } }
  }
});
```

Fix this XState v4 code to v5 idioms — the guard uses the old cond key and positional signature:

```js
const machine = Machine({
  id: 'door',
  initial: 'closed',
  context: { locked: true },
  states: {
    closed: {
      on: {
        OPEN: { target: 'open', cond: (ctx) => !ctx.locked }
      }
    },
    open: {}
  }
});
```

In v5, `cond` becomes `guard`, guards are declared in `setup.guards`, and callbacks use the destructured `({ context })` form.

```typescript
import { setup } from 'xstate';

export const doorMachine = setup({
  types: {
    context: {} as { locked: boolean },
    events: {} as { type: 'OPEN' }
  },
  guards: {
    isUnlocked: ({ context }) => !context.locked
  }
}).createMachine({
  id: 'door',
  initial: 'closed',
  context: { locked: true },
  states: {
    closed: {
      on: {
        OPEN: { target: 'open', guard: 'isUnlocked' }
      }
    },
    open: {}
  }
});
```

Convert this XState v4 machine to v5. It uses the deprecated services key:

```js
const fetchM = Machine({
  id: 'fetch',
  initial: 'loading',
  context: { data: null },
  states: {
    loading: {
      invoke: {
        src: 'loadUser',
        onDone: { target: 'ok', actions: assign({ data: (_, e) => e.data }) },
        onError: 'err'
      }
    },
    ok: {}, err: {}
  }
}, {
  services: { loadUser: () => fetch('/u').then(r => r.json()) }
});
```

v5 replaces the external `services: {}` bag with `setup.actors`, and the promise is wrapped in `fromPromise`. The `onDone` payload is read via `event.output`.

```typescript
import { setup, assign, fromPromise } from 'xstate';

interface User { readonly id: string; readonly name: string }

export const fetchMachine = setup({
  types: {
    context: {} as { data: User | null },
    events: {} as { type: 'RETRY' }
  },
  actors: {
    loadUser: fromPromise<User, void>(async () => {
      const res = await fetch('/u');
      return (await res.json()) as User;
    })
  }
}).createMachine({
  id: 'fetch',
  initial: 'loading',
  context: { data: null },
  states: {
    loading: {
      invoke: {
        src: 'loadUser',
        onDone: { target: 'ok', actions: assign({ data: ({ event }) => event.output }) },
        onError: 'err'
      }
    },
    ok: {},
    err: { on: { RETRY: 'loading' } }
  }
});
```

Fix this XState v4 code to v5 idioms — it mixes positional action signatures and the old Machine factory:

```js
const lightM = Machine({
  id: 'light',
  initial: 'green',
  context: { cycles: 0 },
  states: {
    green:  { on: { NEXT: 'yellow' } },
    yellow: { on: { NEXT: 'red' } },
    red: {
      on: {
        NEXT: {
          target: 'green',
          actions: assign({ cycles: (ctx) => ctx.cycles + 1 })
        }
      }
    }
  }
});
```

Swap `Machine(` for `setup().createMachine`, type the context/events, and use `({ context })` inside `assign`.

```typescript
import { setup, assign } from 'xstate';

export const lightMachine = setup({
  types: {
    context: {} as { cycles: number },
    events: {} as { type: 'NEXT' }
  }
}).createMachine({
  id: 'light',
  initial: 'green',
  context: { cycles: 0 },
  states: {
    green:  { on: { NEXT: 'yellow' } },
    yellow: { on: { NEXT: 'red' } },
    red: {
      on: {
        NEXT: {
          target: 'green',
          actions: assign({ cycles: ({ context }) => context.cycles + 1 })
        }
      }
    }
  }
});
```

Convert this XState v4 machine with internal transition and cond to v5:

```js
const mouse = Machine({
  id: 'mouse',
  initial: 'idle',
  context: { x: 0 },
  states: {
    idle: {
      on: {
        MOVE: {
          actions: assign({ x: (ctx, e) => ctx.x + e.dx }),
          cond: (_ctx, e) => e.dx !== 0,
          internal: true
        }
      }
    }
  }
});
```

In v5, transitions are internal by default (drop `internal: true`); if you wanted a re-entering one you'd set `reenter: true`. `cond` becomes `guard`, and signatures are destructured.

```typescript
import { setup, assign } from 'xstate';

export const mouseMachine = setup({
  types: {
    context: {} as { x: number },
    events: {} as { type: 'MOVE'; dx: number }
  },
  guards: {
    hasDelta: ({ event }) => event.dx !== 0
  }
}).createMachine({
  id: 'mouse',
  initial: 'idle',
  context: { x: 0 },
  states: {
    idle: {
      on: {
        MOVE: {
          guard: 'hasDelta',
          actions: assign({ x: ({ context, event }) => context.x + event.dx })
        }
      }
    }
  }
});
```

Fix this XState v4 fragment to v5 — multiple conds on a single event:

```js
on: {
  SUBMIT: [
    { target: 'ok',   cond: (ctx) => ctx.valid },
    { target: 'warn', cond: (ctx) => ctx.count > 0 },
    { target: 'err' }
  ]
}
```

Convert the `cond` array to `guard` and register the named guards in `setup.guards`. The trailing unguarded entry stays as the fallback.

```typescript
import { setup } from 'xstate';

export const submitMachine = setup({
  types: {
    context: {} as { valid: boolean; count: number },
    events: {} as { type: 'SUBMIT' }
  },
  guards: {
    isValid: ({ context }) => context.valid,
    hasItems: ({ context }) => context.count > 0
  }
}).createMachine({
  id: 'form',
  context: { valid: false, count: 0 },
  initial: 'editing',
  states: {
    editing: {
      on: {
        SUBMIT: [
          { target: 'ok',   guard: 'isValid' },
          { target: 'warn', guard: 'hasItems' },
          { target: 'err' }
        ]
      }
    },
    ok: {}, warn: {}, err: {}
  }
});
```

Convert this XState v4 code to v5. It uses interpret and the old service config:

```js
const m = Machine({ id: 'p', initial: 'a', states: { a: { on: { NEXT: 'b' } }, b: {} } });
const svc = interpret(m).start();
svc.send('NEXT');
```

In v5 there is no `interpret` — use `createActor(machine).start()`. Machine definition moves to `setup().createMachine`.

```typescript
import { setup, createActor } from 'xstate';

const pMachine = setup({
  types: { events: {} as { type: 'NEXT' } }
}).createMachine({
  id: 'p',
  initial: 'a',
  states: { a: { on: { NEXT: 'b' } }, b: {} }
});

const actor = createActor(pMachine).start();
actor.send({ type: 'NEXT' });
```

Fix this XState v4 code to v5 — it uses raise, cond, and positional actions:

```js
const m = Machine({
  id: 'raiser',
  initial: 'a',
  context: { n: 0 },
  states: {
    a: {
      entry: raise('BUMP'),
      on: {
        BUMP: {
          actions: assign({ n: (c) => c.n + 1 }),
          cond: (c) => c.n < 3
        }
      }
    }
  }
});
```

The `raise` helper still exists but now takes an event object; `cond` is `guard`, and the assign callback uses destructuring.

```typescript
import { setup, assign, raise } from 'xstate';

export const raiserMachine = setup({
  types: {
    context: {} as { n: number },
    events: {} as { type: 'BUMP' }
  },
  guards: {
    underLimit: ({ context }) => context.n < 3
  }
}).createMachine({
  id: 'raiser',
  initial: 'a',
  context: { n: 0 },
  states: {
    a: {
      entry: raise({ type: 'BUMP' }),
      on: {
        BUMP: {
          guard: 'underLimit',
          actions: assign({ n: ({ context }) => context.n + 1 })
        }
      }
    }
  }
});
```

Fix this XState v4 fragment to v5 idioms — promise invoke with positional callbacks:

```js
invoke: {
  id: 'save',
  src: (ctx) => api.save(ctx.payload),
  onDone: { target: 'ok', actions: assign({ ref: (_, e) => e.data }) },
  onError: { target: 'err', actions: assign({ err: (_, e) => e.data }) }
}
```

Wrap the promise in `fromPromise`, move the src to `setup.actors`, type the input/output, and read payloads via `event.output` / `event.error`.

```typescript
import { setup, assign, fromPromise } from 'xstate';

interface Payload { readonly body: string }
interface SaveRef { readonly id: string }

declare const api: { save: (p: Payload) => Promise<SaveRef> };

export const saverMachine = setup({
  types: {
    context: {} as { payload: Payload; ref: SaveRef | null; err: unknown },
    events: {} as { type: 'SAVE' }
  },
  actors: {
    save: fromPromise<SaveRef, { payload: Payload }>(({ input }) => api.save(input.payload))
  }
}).createMachine({
  id: 'saver',
  context: { payload: { body: '' }, ref: null, err: null },
  initial: 'idle',
  states: {
    idle: { on: { SAVE: 'saving' } },
    saving: {
      invoke: {
        id: 'save',
        src: 'save',
        input: ({ context }) => ({ payload: context.payload }),
        onDone: { target: 'ok',  actions: assign({ ref: ({ event }) => event.output }) },
        onError: { target: 'err', actions: assign({ err: ({ event }) => event.error }) }
      }
    },
    ok: {}, err: {}
  }
});
```

Each step is a compound substate, the parent catches `onDone` from the `review.submitted` final state, and the BACK transitions move between siblings.

```typescript
import { setup, assign } from 'xstate';

interface FormCtx {
  name: string;
  email: string;
}

type FormEvent =
  | { type: 'NAME'; value: string }
  | { type: 'EMAIL'; value: string }
  | { type: 'NEXT' }
  | { type: 'BACK' }
  | { type: 'SUBMIT' };

export const formMachine = setup({
  types: {
    context: {} as FormCtx,
    events: {} as FormEvent
  }
}).createMachine({
  id: 'form',
  context: { name: '', email: '' },
  initial: 'steps',
  states: {
    steps: {
      initial: 'name',
      onDone: 'done',
      states: {
        name: {
          on: {
            NAME: { actions: assign({ name: ({ event }) => event.value }) },
            NEXT: 'email'
          }
        },
        email: {
          on: {
            EMAIL: { actions: assign({ email: ({ event }) => event.value }) },
            NEXT: 'review',
            BACK: 'name'
          }
        },
        review: {
          initial: 'idle',
          states: {
            idle: { on: { SUBMIT: 'submitted', BACK: '#form.steps.email' } },
            submitted: { type: 'final' }
          }
        }
      }
    },
    done: { type: 'final' }
  }
});
```

Hierarchical states let a parent hold nested substates. Adding a `type: 'history'` child node captures the last active substate so external transitions can target it instead of the `initial` one — exactly the "resume where we left off" pattern.

```typescript
import { setup } from 'xstate';

export const playerMachine = setup({
  types: {
    events: {} as { type: 'PLAY' } | { type: 'PAUSE' } | { type: 'STOP' } | { type: 'RESUME' }
  }
}).createMachine({
  id: 'player',
  initial: 'stopped',
  states: {
    active: {
      initial: 'paused',
      on: { STOP: 'stopped' },
      states: {
        paused:  { on: { PLAY:  'playing' } },
        playing: { on: { PAUSE: 'paused' } },
        hist: { type: 'history', history: 'shallow' }
      }
    },
    stopped: {
      on: { RESUME: '#player.active.hist' }
    }
  }
});
```

Two regions sit under a single `type: 'parallel'` root. They coordinate by raising an internal `PAUSE` event from `network.offline`'s entry, which the queue region listens for.

```typescript
import { setup, raise } from 'xstate';

type E =
  | { type: 'ONLINE' }
  | { type: 'OFFLINE' }
  | { type: 'START' }
  | { type: 'FINISH' }
  | { type: 'PAUSE' };

export const downloaderMachine = setup({
  types: { events: {} as E }
}).createMachine({
  id: 'downloader',
  type: 'parallel',
  states: {
    network: {
      initial: 'online',
      states: {
        online:  { on: { OFFLINE: 'offline' } },
        offline: {
          entry: raise({ type: 'PAUSE' }),
          on: { ONLINE: 'online' }
        }
      }
    },
    queue: {
      initial: 'idle',
      states: {
        idle: { on: { START: 'downloading' } },
        downloading: {
          on: {
            FINISH: 'idle',
            PAUSE:  'idle'
          }
        }
      }
    }
  }
});
```

Each region has its own `initial` and transitions; they live side-by-side under a `type: 'parallel'` root and share a typed event union.

```typescript
import { setup, assign } from 'xstate';

interface ChatCtx { draft: string }

type E =
  | { type: 'OPEN' }
  | { type: 'OPENED' }
  | { type: 'LOST' }
  | { type: 'TYPE'; text: string }
  | { type: 'SEND' }
  | { type: 'SENT' };

export const chatMachine = setup({
  types: { context: {} as ChatCtx, events: {} as E }
}).createMachine({
  id: 'chat',
  context: { draft: '' },
  type: 'parallel',
  states: {
    connection: {
      initial: 'connecting',
      states: {
        connecting:   { on: { OPENED: 'connected', LOST: 'disconnected' } },
        connected:    { on: { LOST: 'disconnected' } },
        disconnected: { on: { OPEN: 'connecting' } }
      }
    },
    composer: {
      initial: 'idle',
      states: {
        idle:    { on: { TYPE: { target: 'typing', actions: assign({ draft: ({ event }) => event.text }) } } },
        typing:  { on: { TYPE: { actions: assign({ draft: ({ event }) => event.text }) }, SEND: 'sending' } },
        sending: { on: { SENT: { target: 'idle', actions: assign({ draft: () => '' }) } } }
      }
    }
  }
});
```

Declare the actor with `fromPromise<Output, Input>` inside `setup.actors`, then reference it from `invoke.src`. The typed `event.output` flows through `onDone`.

```typescript
import { setup, assign, fromPromise } from 'xstate';

interface User { readonly id: string; readonly name: string }

declare function getUser(id: string): Promise<User>;

export const userMachine = setup({
  types: {
    context: {} as { id: string; user: User | null },
    events: {} as { type: 'LOAD' }
  },
  actors: {
    fetchUser: fromPromise<User, { id: string }>(({ input }) => getUser(input.id))
  }
}).createMachine({
  id: 'user',
  context: { id: 'u1', user: null },
  initial: 'idle',
  states: {
    idle: { on: { LOAD: 'loading' } },
    loading: {
      invoke: {
        src: 'fetchUser',
        input: ({ context }) => ({ id: context.id }),
        onDone: { target: 'ok', actions: assign({ user: ({ event }) => event.output }) },
        onError: 'err'
      }
    },
    ok: {},
    err: {}
  }
});
```

A `fromCallback` actor receives `sendBack` for parent-directed events and returns a disposer; cleanup runs when the invoking state exits.

```typescript
import { setup, assign, fromCallback } from 'xstate';

interface WsCtx { lastMessage: string | null }

type E =
  | { type: 'OPEN' }
  | { type: 'CLOSE' }
  | { type: 'MESSAGE'; payload: string };

interface WsLike { onmessage: ((d: string) => void) | null; close: () => void }
declare function openWs(url: string): WsLike;

export const wsMachine = setup({
  types: { context: {} as WsCtx, events: {} as E },
  actors: {
    ws: fromCallback<E, { url: string }>(({ sendBack, input }) => {
      const sock = openWs(input.url);
      sock.onmessage = (data) => sendBack({ type: 'MESSAGE', payload: data });
      return () => sock.close();
    })
  }
}).createMachine({
  id: 'ws',
  context: { lastMessage: null },
  initial: 'closed',
  states: {
    closed: { on: { OPEN: 'open' } },
    open: {
      invoke: { src: 'ws', input: { url: 'wss://example/test' } },
      on: {
        MESSAGE: { actions: assign({ lastMessage: ({ event }) => event.payload }) },
        CLOSE: 'closed'
      }
    }
  }
});
```

The promise actor is wrapped in `fromPromise`, the `onError` transition routes to `error`, and a `RETRY` event brings us back to `saving`.

```typescript
import { setup, assign, fromPromise } from 'xstate';

interface Draft { readonly body: string }
declare function saveDraft(d: Draft): Promise<{ readonly id: string }>;

export const saveMachine = setup({
  types: {
    context: {} as { draft: Draft; id: string | null; error: unknown },
    events: {} as { type: 'SAVE' } | { type: 'RETRY' }
  },
  actors: {
    save: fromPromise<{ readonly id: string }, { draft: Draft }>(({ input }) => saveDraft(input.draft))
  }
}).createMachine({
  id: 'save',
  context: { draft: { body: 'hello' }, id: null, error: null },
  initial: 'idle',
  states: {
    idle: { on: { SAVE: 'saving' } },
    saving: {
      invoke: {
        src: 'save',
        input: ({ context }) => ({ draft: context.draft }),
        onDone: { target: 'done', actions: assign({ id: ({ event }) => event.output.id }) },
        onError: { target: 'error', actions: assign({ error: ({ event }) => event.error }) }
      }
    },
    done: {},
    error: { on: { RETRY: 'saving' } }
  }
});
```

Declare the child with its own `setup().createMachine` (including a `types.output` and a final state's `output`), register it in the parent's `setup.actors`, then invoke with typed `input` and read `event.output` on `onDone`.

```typescript
import { setup, assign } from 'xstate';

const wizardChild = setup({
  types: {
    context: {} as { step: number },
    events: {} as { type: 'NEXT' },
    input: {} as { initialStep: number },
    output: {} as { finalStep: number }
  }
}).createMachine({
  id: 'child',
  context: ({ input }) => ({ step: input.initialStep }),
  initial: 'going',
  states: {
    going: {
      on: {
        NEXT: [
          { target: 'done', guard: ({ context }) => context.step >= 2 },
          { actions: assign({ step: ({ context }) => context.step + 1 }) }
        ]
      }
    },
    done: { type: 'final' }
  },
  output: ({ context }) => ({ finalStep: context.step })
});

export const parentMachine = setup({
  types: { context: {} as { last: number } },
  actors: { wizard: wizardChild }
}).createMachine({
  id: 'parent',
  context: { last: -1 },
  initial: 'running',
  states: {
    running: {
      invoke: {
        src: 'wizard',
        input: { initialStep: 0 },
        onDone: { target: 'done', actions: assign({ last: ({ event }) => event.output.finalStep }) }
      }
    },
    done: { type: 'final' }
  }
});
```

Add a retry button to this v5 fetch machine. It should move from `failure` back to `loading` on RETRY.

```typescript
import { setup, assign, fromPromise } from 'xstate';

declare function getJson(): Promise<{ ok: boolean }>;

export const machine = setup({
  types: { context: {} as { data: { ok: boolean } | null } },
  actors: { load: fromPromise<{ ok: boolean }, void>(() => getJson()) }
}).createMachine({
  id: 'loader',
  context: { data: null },
  initial: 'loading',
  states: {
    loading: {
      invoke: {
        src: 'load',
        onDone: { target: 'ok', actions: assign({ data: ({ event }) => event.output }) },
        onError: 'failure'
      }
    },
    ok: {},
    failure: {}
  }
});
```

Add a `RETRY` event to the typed union and a transition from `failure` back to `loading`.

```typescript
import { setup, assign, fromPromise } from 'xstate';

declare function getJson(): Promise<{ ok: boolean }>;

export const machine = setup({
  types: {
    context: {} as { data: { ok: boolean } | null },
    events: {} as { type: 'RETRY' }
  },
  actors: { load: fromPromise<{ ok: boolean }, void>(() => getJson()) }
}).createMachine({
  id: 'loader',
  context: { data: null },
  initial: 'loading',
  states: {
    loading: {
      invoke: {
        src: 'load',
        onDone: { target: 'ok', actions: assign({ data: ({ event }) => event.output }) },
        onError: 'failure'
      }
    },
    ok: {},
    failure: { on: { RETRY: 'loading' } }
  }
});
```

Use `after` to schedule a delayed transition. Each TYPE re-enters `typing` which cancels the pending timer implicitly; after 500ms of quiet we transition to `searching`.

```typescript
import { setup, assign } from 'xstate';

export const searchMachine = setup({
  types: {
    context: {} as { query: string; results: string[] },
    events: {} as { type: 'TYPE'; q: string } | { type: 'SEARCHED'; hits: string[] }
  }
}).createMachine({
  id: 'search',
  context: { query: '', results: [] },
  initial: 'idle',
  states: {
    idle: {
      on: { TYPE: { target: 'typing', actions: assign({ query: ({ event }) => event.q }) } }
    },
    typing: {
      on: { TYPE: { target: 'typing', reenter: true, actions: assign({ query: ({ event }) => event.q }) } },
      after: {
        500: 'searching'
      }
    },
    searching: {
      on: {
        SEARCHED: { target: 'idle', actions: assign({ results: ({ event }) => event.hits }) }
      }
    }
  }
});
```

Re-entering the same state on `ACTIVITY` resets the `after` delay. The timeout is expressed as a named key so context-driven values could be swapped in later.

```typescript
import { setup } from 'xstate';

export const sessionMachine = setup({
  types: {
    events: {} as { type: 'ACTIVITY' } | { type: 'LOGIN' } | { type: 'LOGOUT' }
  },
  delays: {
    idleTimeout: () => 30 * 60 * 1000
  }
}).createMachine({
  id: 'session',
  initial: 'loggedOut',
  states: {
    loggedOut: { on: { LOGIN: 'active' } },
    active: {
      on: {
        ACTIVITY: { target: 'active', reenter: true },
        LOGOUT: 'loggedOut'
      },
      after: {
        idleTimeout: 'loggedOut'
      }
    }
  }
});
```

Enter a `pending` state with an `after` delay that auto-transitions to `committed`; `UNDO` short-circuits back to `idle`.

```typescript
import { setup } from 'xstate';

export const deleteMachine = setup({
  types: {
    events: {} as { type: 'DELETE' } | { type: 'UNDO' }
  }
}).createMachine({
  id: 'deleter',
  initial: 'idle',
  states: {
    idle: { on: { DELETE: 'pending' } },
    pending: {
      on: { UNDO: 'idle' },
      after: { 5000: 'committed' }
    },
    committed: { type: 'final' }
  }
});
```

Count results in context, use an `always` transition with a guard to move to cooling, and `after` to resume. The counter resets on the transition into `open`.

```typescript
import { setup, assign } from 'xstate';

interface Ctx { count: number }

type E = { type: 'RESULT' };

export const limiterMachine = setup({
  types: { context: {} as Ctx, events: {} as E },
  guards: {
    overLimit: ({ context }) => context.count >= 3
  }
}).createMachine({
  id: 'limiter',
  context: { count: 0 },
  initial: 'open',
  states: {
    open: {
      entry: assign({ count: () => 0 }),
      on: { RESULT: { actions: assign({ count: ({ context }) => context.count + 1 }) } },
      always: { guard: 'overLimit', target: 'cooling' }
    },
    cooling: {
      after: { 2000: 'open' }
    }
  }
});
```

Guards are declared in `setup.guards` and referenced by string in the transition array. The unguarded fallback sits last.

```typescript
import { setup } from 'xstate';

interface Item { sku: string; digital: boolean }

export const checkoutMachine = setup({
  types: {
    context: {} as { items: Item[] },
    events: {} as { type: 'CHECKOUT' }
  },
  guards: {
    hasItems:   ({ context }) => context.items.length > 0,
    allDigital: ({ context }) => context.items.every((i) => i.digital)
  }
}).createMachine({
  id: 'checkout',
  context: { items: [] },
  initial: 'cart',
  states: {
    cart: {
      on: {
        CHECKOUT: [
          { target: 'digital',  guard: 'allDigital' },
          { target: 'shipping', guard: 'hasItems' },
          { target: 'error' }
        ]
      }
    },
    digital: {}, shipping: {}, error: {}
  }
});
```

The higher-order combinators `and`, `or`, `not` compose named guards declared in `setup.guards`. They return `GuardPredicate`s usable directly in transitions.

```typescript
import { setup, and, not } from 'xstate';

interface Ctx {
  userId: string | null;
  blocked: boolean;
  body: string;
}

type E = { type: 'POST'; body: string };

export const moderationMachine = setup({
  types: { context: {} as Ctx, events: {} as E },
  guards: {
    isLoggedIn:   ({ context }) => context.userId !== null,
    isNotBlocked: ({ context }) => !context.blocked,
    isSpam:       ({ event }) => /buy now/i.test(event.body)
  }
}).createMachine({
  id: 'mod',
  context: { userId: null, blocked: false, body: '' },
  initial: 'idle',
  states: {
    idle: {
      on: {
        POST: [
          {
            target: 'posted',
            guard: and(['isLoggedIn', 'isNotBlocked', not('isSpam')])
          },
          { target: 'rejected' }
        ]
      }
    },
    posted: {}, rejected: {}
  }
});
