The event union is a discriminated union on `type`, context holds a readonly array of line items, and every `assign` produces a new array.

```typescript
import { setup, assign } from 'xstate';

interface Line { readonly sku: string; readonly qty: number }
interface CartCtx { readonly lines: ReadonlyArray<Line> }

type CartEvent =
  | { type: 'ADD';    sku: string; qty: number }
  | { type: 'REMOVE'; sku: string }
  | { type: 'CLEAR' };

export const cartMachine = setup({
  types: { context: {} as CartCtx, events: {} as CartEvent }
}).createMachine({
  id: 'cart',
  context: { lines: [] },
  initial: 'open',
  states: {
    open: {
      on: {
        ADD: {
          actions: assign({
            lines: ({ context, event }) => {
              const existing = context.lines.find((l) => l.sku === event.sku);
              if (existing) {
                return context.lines.map((l) =>
                  l.sku === event.sku ? { ...l, qty: l.qty + event.qty } : l
                );
              }
              return [...context.lines, { sku: event.sku, qty: event.qty }];
            }
          })
        },
        REMOVE: {
          actions: assign({
            lines: ({ context, event }) =>
              context.lines.filter((l) => l.sku !== event.sku)
          })
        },
        CLEAR: { actions: assign({ lines: () => [] }) }
      }
    }
  }
});
```

Using a `Map` gives O(1) update by id. The tagged union over TaskState keeps transitions exhaustive.

```typescript
import { setup, assign } from 'xstate';

type TaskState =
  | { tag: 'pending' }
  | { tag: 'running'; startedAt: number }
  | { tag: 'done';    at: number };

interface Ctx { tasks: Map<string, TaskState> }

type E =
  | { type: 'START'; id: string; now: number }
  | { type: 'FINISH'; id: string; now: number }
  | { type: 'ADD'; id: string };

export const boardMachine = setup({
  types: { context: {} as Ctx, events: {} as E }
}).createMachine({
  id: 'board',
  context: { tasks: new Map() },
  initial: 'open',
  states: {
    open: {
      on: {
        ADD: {
          actions: assign({
            tasks: ({ context, event }) => {
              const next = new Map(context.tasks);
              next.set(event.id, { tag: 'pending' });
              return next;
            }
          })
        },
        START: {
          actions: assign({
            tasks: ({ context, event }) => {
              const next = new Map(context.tasks);
              next.set(event.id, { tag: 'running', startedAt: event.now });
              return next;
            }
          })
        },
        FINISH: {
          actions: assign({
            tasks: ({ context, event }) => {
              const next = new Map(context.tasks);
              next.set(event.id, { tag: 'done', at: event.now });
              return next;
            }
          })
        }
      }
    }
  }
});
```

