Gate the `raise` on a named guard using `enqueueActions` + `check`. Only fire OVERFLOW when the counter crosses the threshold.

```typescript
import { setup, enqueueActions } from 'xstate';

export const m = setup({
  types: { context: {} as { n: number }, events: {} as { type: 'STEP' } | { type: 'OVERFLOW' } },
  guards: {
    willOverflow: ({ context }) => context.n + 1 >= 3
  }
}).createMachine({
  id: 'm',
  context: { n: 0 },
  initial: 'a',
  states: {
    a: {
      on: {
        STEP: {
          actions: enqueueActions(({ enqueue, check }) => {
            enqueue.assign({ n: ({ context }) => context.n + 1 });
            if (check('willOverflow')) {
              enqueue.raise({ type: 'OVERFLOW' });
            }
          })
        },
        OVERFLOW: 'b'
      }
    },
    b: {}
  }
});
```

