`fromTransition((state, event) => nextState, initialState)` builds an actor logic from a reducer. Invoke it like any other actor declared in `setup.actors`.

```typescript
import { setup, fromTransition } from 'xstate';

type CE = { type: 'INC' } | { type: 'DEC' };

const counterLogic = fromTransition(
  (state: { n: number }, event: CE) => {
    if (event.type === 'INC') return { n: state.n + 1 };
    if (event.type === 'DEC') return { n: state.n - 1 };
    return state;
  },
  { n: 0 }
);

export const hostMachine = setup({
  types: { events: {} as { type: 'START' } },
  actors: { counter: counterLogic }
}).createMachine({
  id: 'host',
  initial: 'idle',
  states: {
    idle: { on: { START: 'running' } },
    running: { invoke: { id: 'ctr', src: 'counter' } }
  }
});
```

Named delays in `setup.delays` receive `({ context })` and return a number, letting per-instance timings flow from context.

```typescript
import { setup } from 'xstate';

interface Ctx {
  greenMs:  number;
  yellowMs: number;
  redMs:    number;
}

type E = { type: 'RESET' };

export const trafficMachine = setup({
  types: { context: {} as Ctx, events: {} as E },
  delays: {
    greenDelay:  ({ context }) => context.greenMs,
    yellowDelay: ({ context }) => context.yellowMs,
    redDelay:    ({ context }) => context.redMs
  }
}).createMachine({
  id: 'traffic',
  context: { greenMs: 5000, yellowMs: 1500, redMs: 4000 },
  initial: 'green',
  states: {
    green:  { after: { greenDelay:  'yellow' } },
    yellow: { after: { yellowDelay: 'red'    } },
    red:    { after: { redDelay:    'green'  } }
