When the state exits, XState stops the invoked actor, so a `CANCEL` transition out of `uploading` implicitly cancels the in-flight promise. The context holds typed progress.

```typescript
import { setup, assign, fromPromise } from 'xstate';

interface File { readonly name: string; readonly bytes: number }
interface Receipt { readonly id: string }

declare function upload(f: File): Promise<Receipt>;

export const uploadMachine = setup({
  types: {
    context: {} as { file: File; receipt: Receipt | null; error: unknown },
    events: {} as { type: 'START' } | { type: 'CANCEL' }
  },
  actors: {
    uploader: fromPromise<Receipt, { file: File }>(({ input }) => upload(input.file))
  }
}).createMachine({
  id: 'upload',
  context: { file: { name: 'a.txt', bytes: 0 }, receipt: null, error: null },
  initial: 'idle',
  states: {
    idle: { on: { START: 'uploading' } },
    uploading: {
      invoke: {
        src: 'uploader',
        input: ({ context }) => ({ file: context.file }),
        onDone: { target: 'done',  actions: assign({ receipt: ({ event }) => event.output }) },
        onError: { target: 'error', actions: assign({ error:   ({ event }) => event.error }) }
      },
      on: { CANCEL: 'cancelled' }
    },
    done: {}, error: {}, cancelled: {}
  }
});
```

