A global `on.LOGOUT` at the root targets `unauth.form` regardless of the current substate. Inside `unauth`, a `fromPromise` handles the sign-in call.

```typescript
import { setup, assign, fromPromise } from 'xstate';

interface Creds { email: string; password: string }
interface Session { token: string }

declare function signIn(c: Creds): Promise<Session>;

export const authMachine = setup({
  types: {
    context: {} as { creds: Creds; session: Session | null },
    events: {} as { type: 'SUBMIT' } | { type: 'LOGOUT' } | { type: 'EXPIRE' }
  },
  actors: {
    signIn: fromPromise<Session, { creds: Creds }>(({ input }) => signIn(input.creds))
  }
}).createMachine({
  id: 'auth',
  context: { creds: { email: '', password: '' }, session: null },
  initial: 'unauth',
  on: { LOGOUT: '.unauth.form' },
  states: {
    unauth: {
      initial: 'form',
      states: {
        form: { on: { SUBMIT: 'submitting' } },
        submitting: {
          invoke: {
            src: 'signIn',
            input: ({ context }) => ({ creds: context.creds }),
            onDone: {
              target: '#auth.auth.active',
              actions: assign({ session: ({ event }) => event.output })
            },
            onError: 'form'
          }
        }
      }
    },
    auth: {
      initial: 'active',
      states: {
        active:  { on: { EXPIRE: 'expired' } },
        expired: {}
      }
    }
  }
});
```
